/// Word index for search acceleration.
/// Maps common words to term indices.
#[doc(hidden)]
pub mod search_index {
    // Search index implementation would go here
    // For now, linear search is used in search_terms()
}

/// Look up a term by exact name (case-insensitive).
///
/// Uses binary search for O(log n) lookup.
///
/// # Example
///
/// ```rust,ignore
/// use nexcore_vigilance::coding::glossary::lookup_term;
///
/// if let Some(term) = lookup_term("adverse event") {
///     println!("{}", term.definition);
/// }
/// ```
#[must_use]
pub fn lookup_term(name: &str) -> Option<&'static GlossaryTerm> {
    let key = name.to_lowercase();
    GLOSSARY
        .binary_search_by_key(&&*key, |(k, _)| *k)
        .ok()
        .map(|i| &GLOSSARY[i].1)
}

/// Get all terms in the glossary.
#[must_use]
pub fn all_terms() -> impl Iterator<Item = &'static GlossaryTerm> {
    GLOSSARY.iter().map(|(_, t)| t)
}

/// Get the total number of terms.
#[must_use]
pub const fn term_count() -> usize {
    GLOSSARY.len()
}

/// Search terms by substring match (case-insensitive).
///
/// Returns up to `limit` matching terms.
#[must_use]
pub fn search_terms(query: &str, limit: usize) -> Vec<&'static GlossaryTerm> {
    let query_lower = query.to_lowercase();

    GLOSSARY
        .iter()
        .filter(|(key, term)| {
            key.contains(&query_lower) || term.definition.to_lowercase().contains(&query_lower)
        })
        .take(limit)
        .map(|(_, t)| t)
        .collect()
}

/// Search terms by word prefix.
#[must_use]
pub fn search_by_prefix(prefix: &str, limit: usize) -> Vec<&'static GlossaryTerm> {
    let prefix_lower = prefix.to_lowercase();

    GLOSSARY
        .iter()
        .filter(|(key, _)| key.starts_with(&prefix_lower))
        .take(limit)
        .map(|(_, t)| t)
        .collect()
}

/// Get terms from a specific source (ICH, CIOMS, etc.).
#[must_use]
pub fn terms_by_source(source: &str) -> Vec<&'static GlossaryTerm> {
    GLOSSARY
        .iter()
        .filter(|(_, t)| t.source.eq_ignore_ascii_case(source))
        .map(|(_, t)| t)
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_term_count() {
        assert!(term_count() > 0, "Glossary should have terms");
    }

    #[test]
    fn test_all_terms_iterator() {
        let count = all_terms().count();
        assert_eq!(count, term_count());
    }

    #[test]
    fn test_search_terms() {
        let results = search_terms("adverse", 10);
        assert!(!results.is_empty(), "Should find terms with 'adverse'");
    }

    #[test]
    fn test_case_insensitive_lookup() {
        // Lookup should be case-insensitive
        let lower = lookup_term("adverse event");
        let upper = lookup_term("ADVERSE EVENT");
        let mixed = lookup_term("Adverse Event");
        assert_eq!(lower, upper);
        assert_eq!(upper, mixed);
    }

    #[test]
    fn test_lookup_absolute_risk() {
        let result = lookup_term("absolute risk");
        assert!(result.is_some(), "Term should exist: Absolute risk");
        let term = result.expect("term exists");
        assert_eq!(term.term, "Absolute risk");
    }

    #[test]
    fn test_lookup_academia() {
        let result = lookup_term("academia");
        assert!(result.is_some(), "Term should exist: Academia");
        let term = result.expect("term exists");
        assert_eq!(term.term, "Academia");
    }

    #[test]
    fn test_lookup_accelerated_studies() {
        let result = lookup_term("accelerated studies");
        assert!(result.is_some(), "Term should exist: Accelerated Studies");
        let term = result.expect("term exists");
        assert_eq!(term.term, "Accelerated Studies");
    }
}
